#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int a, K, x1, x2, x3;
        scanf("%d %d %d %d %d", &a, &K, &x1, &x2, &x3);
        int min_x = x1;
        int max_x = x1;
        if (x2 < min_x) min_x = x2;
        if (x2 > max_x) max_x = x2;
        if (x3 < min_x) min_x = x3;
        if (x3 > max_x) max_x = x3;
        int intersection = a;
        if (max_x - min_x > 2 * a) intersection = 0;
        else if (max_x - min_x > a) intersection = a - (max_x - min_x - a);
        printf("%.6f\n", (double)intersection * intersection);
    }
    return 0;
}

