import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int a = sc.nextInt();
            int K = sc.nextInt();
            int x1 = sc.nextInt();
            int x2 = sc.nextInt();
            int x3 = sc.nextInt();
            int min_x = Math.min(x1, Math.min(x2, x3));
            int max_x = Math.max(x1, Math.max(x2, x3));
            int intersection = a;
            if (max_x - min_x > 2 * a) intersection = 0;
            else if (max_x - min_x > a) intersection = a - (max_x - min_x - a);
            System.out.printf("%.6f\n", (double)intersection * intersection);
        }
    }
}

